4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[true]])).toEqual([[]]);
10	  });
11	  it("should return empty grid for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[true, true]])).toEqual([[]]);
13	  });
14	  it("should keep a block (2x2) unchanged as a still life", () => {
15	    const block = [
16	      [true, true],
17	      [true, true],
18	    ];
19	    expect(nextGeneration(block)).toEqual([
20	      [true, true],
21	      [true, true],
22	    ]);
23	  });
24	  it("should transform a vertical blinker to a horizontal blinker", () => {
25	    const verticalBlinker = [[true], [true], [true]];
26	    const horizontalBlinker = [[], [true, true, true], []];
27	    expect(nextGeneration(verticalBlinker)).toEqual(horizontalBlinker);
28	  });
